const body = $('Webhook').item.json.body || {};
let msgType = 'text', msgText = '', mediaUrl = '', fromMe = body.fromMe || false;

if (body.audio?.audioUrl)            { msgType = 'audio';    mediaUrl = body.audio.audioUrl; }
else if (body.image?.imageUrl)       { msgType = 'image';    mediaUrl = body.image.imageUrl;        msgText = body.image.caption    || ''; }
else if (body.video?.videoUrl)       { msgType = 'video';    mediaUrl = body.video.videoUrl;        msgText = body.video.caption    || ''; }
else if (body.document?.documentUrl) { msgType = 'document'; mediaUrl = body.document.documentUrl; msgText = body.document.caption || ''; }
else if (body.text?.message)         { msgType = 'text';     msgText  = body.text.message; }
else if (body.sticker)               { msgType = 'sticker'; }
else if (body.reaction)              { msgType = 'reaction'; msgText = body.reaction.value || ''; }
else                                 { msgType = 'unknown'; }

const msgId = body.messageId || ('id_' + Date.now() + '_' + Math.random().toString(36).slice(2));
return [{ json: { msgType, msgText, mediaUrl, fromMe, phone: body.phone || '', msgId } }];

const rows  = $input.all();
const myId  = String($('Detectar Tipo de Mensagem').item.json.msgId || '');
const now   = Date.now();

if (!rows || rows.length === 0) {
  return [{ json: { skip: true, reason: 'fila vazia', aggregatedText: '', msgType: 'text', rows: [] } }];
}

const sorted = rows.slice().sort((a, b) => {
  const ta = Number(a.json.timestamp || 0);
  const tb = Number(b.json.timestamp || 0);
  return ta - tb;
});

// Se há mensagem fromMe nos últimos 30s → agente já respondeu, descarta
const recentFromMe = sorted.find(r => {
  const isFromMe = r.json.fromMe === 'sim';
  const age = now - Number(r.json.timestamp || 0);
  return isFromMe && age < 30000;
});

if (recentFromMe) {
  return [{ json: { skip: true, reason: 'agente respondeu recentemente', aggregatedText: '', msgType: 'text', rows: [] } }];
}

// Filtra apenas mensagens do paciente (não fromMe)
const patientRows = sorted.filter(r => r.json.fromMe !== 'sim');

if (patientRows.length === 0) {
  return [{ json: { skip: true, reason: 'sem mensagens do paciente', aggregatedText: '', msgType: 'text', rows: [] } }];
}

const lastRow = patientRows[patientRows.length - 1];
const lastId  = String(lastRow.json.msgId || '');

if (lastId !== myId) {
  return [{ json: { skip: true, reason: 'nao e o dono', aggregatedText: '', msgType: 'text', rows: [] } }];
}

const texts = patientRows
  .map(r => (String(r.json.msgText || '')).trim())
  .filter(t => t.length > 0)
  .join('\n');

const lastMsgType  = String(lastRow.json.msgType || 'text');
const lastMediaUrl = (String(lastRow.json.mediaUrl || '')).replace(/^'+/, '');

return [{
  json: {
    skip: false,
    aggregatedText: texts || '[mensagem sem texto]',
    msgType: lastMsgType,
    mediaUrl: lastMediaUrl,
    rowCount: patientRows.length,
    rows: sorted.map(r => r.json),
    pacientePhone: $('Campos Personalizados').item.json['📞 | Telefone WhatsApp']
  }
}];

const debounce     = $('Verificar Dono da Fila').item.json;
const aggregated   = debounce.aggregatedText || '[mensagem sem texto]';
const msgType      = debounce.msgType;

let transcription = '';
try { transcription = $('Transcrição do áudio').item?.json?.text || ''; } catch(e) {}

let visionResult = '';
try { 
  visionResult = $('Analisar Imagem [Vision]').item?.json?.choices?.[0]?.message?.content || '';
} catch(e) {}

let finalText = aggregated;

if (transcription) {
  finalText = '[Áudio transcrito]: ' + transcription;
  if (aggregated && aggregated !== '[mensagem sem texto]') finalText += '\n' + aggregated;
}
if (visionResult) {
  finalText += '\n[ANALISE_IMAGEM]: ' + visionResult;
}


const isFirstMsg = !(debounce.rows && debounce.rows.length > 1);


// Se for primeira mensagem e for apenas um número (escolha do menu),
// adicionar contexto de pós-operatório
let contextText = finalText;
if (isFirstMsg && /^[1-4]$/.test(finalText.trim())) {
  contextText = '[Paciente acabou de iniciar atendimento de pós-operatório. Faça uma saudação e pergunte como pode ajudar.]';
}

return [{ json: { 
  text: contextText, 
  msgType,
  firstMessage: isFirstMsg
} }];

const agentOutput = items[0].json.output;
const rawOutput = agentOutput.output || agentOutput;
let jsonString = (typeof rawOutput === 'string') ? rawOutput : JSON.stringify(rawOutput);
jsonString = jsonString
  .replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
let parsedJson;
try { parsedJson = JSON.parse(jsonString); }
catch (e) { parsedJson = { messages: [jsonString], DISPARAR_ALERTA: false, alerta_resumo: '', PRECISA_MAIKON: false, duvida_maikon: '' }; }

if (parsedJson.PRECISA_MAIKON === undefined) parsedJson.PRECISA_MAIKON = false;
if (parsedJson.duvida_maikon === undefined) parsedJson.duvida_maikon = '';
if (parsedJson.DISPARAR_ALERTA === undefined) parsedJson.DISPARAR_ALERTA = false;
if (parsedJson.alerta_resumo === undefined) parsedJson.alerta_resumo = '';

return [{ json: parsedJson }];

// Busca resultado do checklist do dia
let checkRow = null;
try { checkRow = $('Buscar Checklist [Google Sheets]').item?.json; } catch(e) {}

const hoje = $now.toFormat('yyyy-MM-dd');
const jaExiste = checkRow && checkRow.data === hoje;

const checklist = {
  noite:    jaExiste ? (checkRow.noite    || 'nao') : 'nao',
  pressao:  jaExiste ? (checkRow.pressao  || 'nao') : 'nao',
  sol:      jaExiste ? (checkRow.sol      || 'nao') : 'nao',
  caminhada: jaExiste ? (checkRow.caminhada || 'nao') : 'nao',
  jaExiste
};

const pendentes = [];
if (checklist.noite     === 'nao') pendentes.push('como_foi_a_noite');
if (checklist.pressao   === 'nao') pendentes.push('pressao_arterial');
if (checklist.sol       === 'nao') pendentes.push('sol_30min');
if (checklist.caminhada === 'nao') pendentes.push('caminhada');

return [{ json: { checklist, pendentes, hoje } }];

// Extrai do output do agente quais itens foram cobertos nessa interação
const parsed = $('Code1').item.json;
const checklistAtualizado = parsed.checklist_update || {};

// Lê estado atual
let checkRow = null;
try { checkRow = $('Buscar Checklist [Google Sheets]').item?.json; } catch(e) {}
const hoje = $now.toFormat('yyyy-MM-dd');
const jaExiste = checkRow && checkRow.data === hoje;

const noite     = checklistAtualizado.noite     || (jaExiste ? checkRow.noite     : 'nao') || 'nao';
const pressao   = checklistAtualizado.pressao   || (jaExiste ? checkRow.pressao   : 'nao') || 'nao';
const sol       = checklistAtualizado.sol       || (jaExiste ? checkRow.sol       : 'nao') || 'nao';
const caminhada = checklistAtualizado.caminhada || (jaExiste ? checkRow.caminhada : 'nao') || 'nao';

return [{ json: {
  phone: $('Campos Personalizados1').item.json['📞 | Telefone WhatsApp'],
  data: hoje,
  noite, pressao, sol, caminhada,
  jaExiste,
  row_number: jaExiste ? checkRow.row_number : null
}}];

const parsed = $('Code').item.json;
const phone = $('Campos Personalizados').item.json['📞 | Telefone WhatsApp'] || 'desconhecido';
const resumo = parsed.alerta_resumo || 'Sem detalhes';

const msg = '🚨 *ALERTA PACIENTE* 🚨\n\n' +
  'Paciente: ' + phone + '\n' +
  resumo + '\n\n' +
  'Verifique o WhatsApp do paciente.';

return [{ json: { alertMsg: msg, phone } }];

const raw = items[0].json.output || items[0].json.text || '';
let jsonString = (typeof raw === 'string') ? raw : JSON.stringify(raw);
jsonString = jsonString.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```$/i,'').trim();
let parsed;
try { parsed = JSON.parse(jsonString); }
catch(e) { parsed = { messages: [jsonString] }; }
return [{ json: parsed }];

const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
let ref = '';
for (let i = 0; i < 4; i++) ref += chars[Math.floor(Math.random() * chars.length)];
return [{ json: { ref_id: ref } }];

const text = String($('Detectar Tipo de Mensagem').item.json.msgText || '');
const match = text.match(/#([A-Z0-9]{4})/i);
const ref_id = match ? match[1].toUpperCase() : '';
const resposta = text.replace(/#[A-Z0-9]{4}\s*/i, '').trim();
return [{ json: { ref_id, resposta_maikon: resposta } }];

const msg     = (String($('Detectar Tipo de Mensagem').item.json.msgText || '')).trim();
const triagem = $('Verificar Triagem [Google Sheets]').item.json;
const msgType = $('Detectar Tipo de Mensagem').item.json.msgType || 'text';

// Reset manual pelo paciente
if (/^0$|^menu$|^voltar$|^inicio$|^início$/i.test(msg)) {
  return [{ json: { opcao: '', destino: 'menu', msg, reset: true } }];
}

// Reset após 3 dias
const RESET_MS  = 3 * 24 * 60 * 60 * 1000;
const agora     = Date.now();
const tsTriagem = triagem.timestamp ? new Date(triagem.timestamp).getTime() : 0;
const expirado  = tsTriagem > 0 && (agora - tsTriagem) > RESET_MS;

// Se expirado → menu
if (expirado) {
  return [{ json: { opcao: '', destino: 'menu', msg, expirado: true } }];
}

// Se já tem opção salva e ativo → roteia direto sem pedir menu de novo
if (triagem.status === 'ativo' && triagem.opcao) {
  const opcaoStr = String(triagem.opcao);
  const destino = opcaoStr === '2' ? 'agente' : 'encerrado';
  return [{ json: { opcao: triagem.opcao, destino, nome: triagem.nome || '', expirado: false } }];
}

// Se for áudio → ignora silenciosamente
if (msgType === 'audio' || msgType === 'ptt') {
  return [{ json: { opcao: '', destino: 'encerrado', msg, motivo: 'audio_sem_opcao' } }];
}

// Detectar opção pelo texto — regex ampliada para linguagem natural
let opcao = '';

if (/\b1\b|^1$|1️⃣|pré.operat|pre.operat|antes da cirurg|pré.op|pre.op/i.test(msg)) {
  opcao = '1';
} else if (/\b2\b|^2$|2️⃣|pós.operat|pos.operat|depois da cirurg|pós.op|pos.op/i.test(msg)) {
  opcao = '2';
} else if (/\b3\b|^3$|3️⃣|agend|consult|marcar|agendar/i.test(msg)) {
  opcao = '3';
} else if (/\b4\b|^4$|4️⃣|exam|prescri|receita|resultado/i.test(msg)) {
  opcao = '4';
}

// Se não detectou opção → silêncio (não reenvia menu)
// O paciente pode estar digitando algo fora do contexto ou mandando saudação
// Apenas o menu original já está visível para ele
if (!opcao) {
  return [{ json: { opcao: '', destino: 'encerrado', msg, motivo: 'mensagem_invalida' } }];
}

const destino = opcao === '2' ? 'agente' : 'secretaria';
return [{ json: { opcao, destino, msg, expirado: false } }];

const opcao = $('Detectar Opção [Code]').item.json.opcao || '';
const phone = $('Campos Personalizados').item.json['📞 | Telefone WhatsApp'] || '';
const nome  = $('Campos Personalizados').item.json['👤 | Nome do Paciente'] || 'Paciente';
const msg   = String($('Detectar Tipo de Mensagem').item.json.msgText || '');

const labels = { '1': 'Pré-operatório', '3': 'Agendamento de consulta', '4': 'Exames e prescrições' };
const label = labels[opcao] || 'Não identificado';

const alerta = `📋 *NOVO CONTATO NO CONSULTÓRIO*

👤 Paciente: ${nome}
📞 Telefone: ${phone}
📌 Assunto: ${label}

💬 Mensagem: ${msg}

Por favor, entre em contato com o paciente.`;

return [{ json: { alerta } }];
